patch:
diff --git a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
index d7afe2f426d3..f004a794247b 100644
--- a/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
+++ b/llvm/lib/Transforms/Vectorize/VectorCombine.cpp
@@ -2595,7 +2595,22 @@ bool VectorCombine::shrinkType(llvm::Instruction &I) {

   auto *BigTy = cast<FixedVectorType>(I.getType());
   auto *SmallTy = cast<FixedVectorType>(ZExted->getType());
+  unsigned BigBW = BigTy->getElementType()->getPrimitiveSizeInBits();
   unsigned BW = SmallTy->getElementType()->getPrimitiveSizeInBits();
+  // For LShr, the shift amount must be less than the bitwidth of the small type.
+  if (I.getOpcode() == Instruction::LShr) {
+    KnownBits ShiftKB = computeKnownBits(OtherOperand, *DL);
+    // Compute the maximum possible value of the shift amount modulo (1 << BW).
+    APInt MaxShiftAmount = ShiftKB.getMaxValue();
+    APInt Mask = APInt::getLowBitsSet(MaxShiftAmount.getBitWidth(), BW);
+    // Also ensure shift amount is less than the original bitwidth.
+    if (MaxShiftAmount.uge(BigBW))
+      return false;
+    APInt MaxMod = MaxShiftAmount & Mask;
+    // If the maximum modulo value could be >= BW, bail out.
+    if (MaxMod.uge(BW))
+      return false;
+  }

   // Check that the expression overall uses at most the same number of bits as
   // ZExted

